class AllOne {
public:
    AllOne() {

    }

    void inc(string key) {
        if (m.count(key)) {
            m[key]++;
            bucket[m[key] - 1].erase(key);
            bucket[m[key]].insert(key);
        } else {
            m[key] = 1;
            bucket[1].insert(key);
        }
    }

    void dec(string key) {
        if (m.count(key)) {
            bucket[m[key]].erase(key);
            if (m[key] > 1) {
                m[key]--;
                bucket[m[key]].insert(key);
            } else {
                m.erase(key);
            }
        }
    }

    string getMaxKey() {
        if (m.empty()) return "";
        return *(--bucket.rbegin()->second.end());
    }

    string getMinKey() {
        if (m.empty()) return "";
        return *(bucket.begin()->second.begin());
    }
private:
    unordered_map<string, int> m;
    unordered_map<int, unordered_set<string>> bucket;
};
